#!/usr/bin/env python3
"""
sincronizar_painel.py
Atualiza o painel-fundef-acp.html com os dados mais recentes da planilha
FUNDEF ACP - BRASIL no Google Sheets.

Uso:
    python sincronizar_painel.py

Dependencias:
    pip install -r requirements.txt

Na primeira execucao abrira uma janela do navegador para autorizar o acesso.
As credenciais sao salvas em token.json e reutilizadas nas proximas execucoes.
"""

import os, sys, re, json, csv, io, base64
from pathlib import Path
from datetime import datetime

# -- Configuracao --------------------------------------------------------------
FILE_ID     = "192kkhxtCzeruq_Kc0boTrOAYcph2--x5k7bA13-4ev0"   # ID da planilha (Google Sheets)
SCOPES      = ["https://www.googleapis.com/auth/drive.readonly"]
CREDENTIALS = "credentials.json"   # baixe do Google Cloud Console
TOKEN_FILE  = "token.json"
OUTPUT_HTML = "painel-fundef-acp.html"

# -- Template HTML (codificado em base64 para evitar problemas de escaping) ----
_TMPL_BEFORE_B64 = ""
_TMPL_AFTER_B64  = ""

TMPL_BEFORE = base64.b64decode(_TMPL_BEFORE_B64).decode("utf-8")
TMPL_AFTER  = base64.b64decode(_TMPL_AFTER_B64).decode("utf-8")

# -- Google Drive auth -----------------------------------------------------------
SERVICE_ACCOUNT_FILE = "service_account.json"
SERVICE_ACCOUNT_ENV  = "GOOGLE_SERVICE_ACCOUNT_JSON"


def get_drive_service():
    """
    Escolhe o metodo de autenticacao automaticamente:

    1. Conta de servico (para automacao, ex: GitHub Actions):
       - variavel de ambiente GOOGLE_SERVICE_ACCOUNT_JSON com o conteudo do JSON, OU
       - arquivo service_account.json na pasta
       Nao abre navegador - ideal para rodar em servidor/CI.

    2. OAuth pessoal (para uso manual no seu computador):
       - credentials.json + token.json (fluxo original)
       Abre o navegador na primeira vez para autorizar.
    """
    try:
        from google.oauth2 import service_account as gsa
        from googleapiclient.discovery import build
    except ImportError:
        print("\nDependencias ausentes. Execute:")
        print("   pip install -r requirements.txt")
        sys.exit(1)

    # --- 1. Conta de servico ---------------------------------------------------
    sa_json = os.environ.get(SERVICE_ACCOUNT_ENV)
    if sa_json:
        info = json.loads(sa_json)
        creds = gsa.Credentials.from_service_account_info(info, scopes=SCOPES)
        return build("drive", "v3", credentials=creds)

    if Path(SERVICE_ACCOUNT_FILE).exists():
        creds = gsa.Credentials.from_service_account_file(SERVICE_ACCOUNT_FILE, scopes=SCOPES)
        return build("drive", "v3", credentials=creds)

    # --- 2. OAuth pessoal (fluxo original, com navegador) -----------------------
    from google.oauth2.credentials import Credentials
    from google_auth_oauthlib.flow import InstalledAppFlow
    from google.auth.transport.requests import Request

    creds = None
    if Path(TOKEN_FILE).exists():
        creds = Credentials.from_authorized_user_file(TOKEN_FILE, SCOPES)

    if not creds or not creds.valid:
        if creds and creds.expired and creds.refresh_token:
            creds.refresh(Request())
        else:
            if not Path(CREDENTIALS).exists():
                print(f"\nNenhuma credencial encontrada.")
                print(f"   Crie {SERVICE_ACCOUNT_FILE!r} (conta de servico) ou {CREDENTIALS!r} (OAuth pessoal).")
                print("   Siga as instrucoes em COMO_CONFIGURAR.md.")
                sys.exit(1)
            flow = InstalledAppFlow.from_client_secrets_file(CREDENTIALS, SCOPES)
            creds = flow.run_local_server(port=0)
        with open(TOKEN_FILE, "w") as f:
            f.write(creds.to_json())

    return build("drive", "v3", credentials=creds)


# -- Download da planilha como CSV ------------------------------------------------
def download_csv(service, file_id: str) -> str:
    """Exporta um Google Sheets nativo como CSV (primeira aba)."""
    from googleapiclient.http import MediaIoBaseDownload
    request = service.files().export_media(
        fileId=file_id,
        mimeType="text/csv"
    )
    buf = io.BytesIO()
    downloader = MediaIoBaseDownload(buf, request)
    done = False
    while not done:
        _, done = downloader.next_chunk()
    return buf.getvalue().decode("utf-8", errors="replace")


# -- Parsing ------------------------------------------------------------------------
def clean(v: str) -> str:
    v = (v or "").strip()
    return "" if v == "*" else v


def parse_valor_br(s: str) -> float:
    """Converte valores no formato brasileiro 'R$ 1.234.567,89' para float.

    Retorna 0.0 para qualquer valor que nao tenha cara de quantia monetaria
    (ex: numeros de processo digitados por engano na coluna de valor, como
    '1071519-32.2023.4.01.3400').
    """
    s = clean(s)
    if not s:
        return 0.0
    upper = s.upper()
    if any(x in upper for x in ["NAO", "NÃO", "AINDA", "NENHUM", "CONCORDOU",
                                  "SIM", "TEM", "LOCALIZ", "PENDENTE",
                                  "CANCELADO", "PAGO", "RECOMP", "BLOQUEADO"]):
        return 0.0
    # Numero de processo (NNNNNNN-DD.AAAA.J.TR.OOOO) contem '-': descarta
    if "-" in s:
        return 0.0
    nums = re.sub(r"[^\d.,]", "", s)
    if not nums:
        return 0.0
    # Formato brasileiro: ponto = milhar, virgula = decimal
    nums = nums.replace(".", "").replace(",", ".")
    # Valores monetarios reais da planilha nao chegam a R$ 1 trilhao (13 digitos);
    # qualquer coisa maior provavelmente e lixo/numero de processo mal colado
    digit_count = len(re.sub(r"\D", "", nums))
    if digit_count > 13:
        return 0.0
    try:
        return float(nums)
    except ValueError:
        return 0.0


def parse_planilha(csv_text: str) -> list[dict]:
    """
    Estrutura da planilha (27 colunas, indices 0-26):
      0  UF                          1  MUNICIPIO
      2  PROCESSO                    3  VARA
      4  VALOR                       5  PERIODO
      6  AGRAVO DE INCOMPETENCIA     7  STATUS COMP.
      8  AGRAVO PRC                  9  STATUS INCONT.
     10  AGRAVO MERITO DA UNIAO     11  STATUS MERITO
     12  AGRAVO MERITO DO MUNICIPIO 13  STATUS MERITO
     14  PREVENTO                   15  INCONTROVERSO
     16  CONTADORIA                 17  JULGADA IMPUGNACAO
     18  RESUMO                     19  PRC
     20  STATUS PRC                 21  ATUALIZACAO
     22  PROVIDENCIA                23  CONTRATO
     24  PROCURACAO                 25  PENDENCIA DOCUMENTAL
     26  (coluna extra/vazia)
    """
    reader = csv.reader(io.StringIO(csv_text))
    rows = list(reader)
    if len(rows) < 2:
        return []

    records = []
    for row in rows[1:]:
        if len(row) < 20:
            continue

        def col(idx):
            return clean(row[idx]) if len(row) > idx else ""

        municipio = col(1)
        processo  = col(2)
        if not municipio and not processo:
            continue

        r = {
            "UF":                 col(0),
            "MUNICIPIO":          municipio,
            "PROCESSO":           processo,
            "VARA":               col(3),
            "VALOR":              col(4),
            "PERIODO":            col(5),
            "PREVENTO":           col(14),
            "INCONTROVERSO":      col(15),
            "CONTADORIA":         col(16),
            "JULGADA_IMPUGNACAO": col(17),
            "PRC":                col(19),
            "STATUS_PRC":         col(20),
            "ATUALIZACAO":        col(21),
            "PROVIDENCIA":        col(22),
            "CONTRATO":           col(23),
            "PENDENCIA_DOC":      col(25),
        }
        r["VALOR_NUM"] = parse_valor_br(r["VALOR"])
        r["INCON_NUM"] = parse_valor_br(r["INCONTROVERSO"])
        r["CONT_NUM"]  = parse_valor_br(r["CONTADORIA"])
        records.append(r)

    return records


# -- Geracao do HTML -----------------------------------------------------------------
def build_html(records: list[dict]) -> str:
    data_json = json.dumps(records, ensure_ascii=False, separators=(",", ":"))
    return TMPL_BEFORE + data_json + TMPL_AFTER


# -- Main --------------------------------------------------------------------------------
def main():
    t0 = datetime.now()
    print("=" * 56)
    print("  Sincronizador - Painel FUNDEF ACP")
    print("=" * 56)

    print("\n[1/3] Autenticando no Google Drive...")
    service = get_drive_service()
    print("      OK - Autenticado")

    print("\n[2/3] Baixando planilha...")
    csv_text = download_csv(service, FILE_ID)
    print(f"      OK - {len(csv_text):,} caracteres recebidos")

    records = parse_planilha(csv_text)
    print(f"      OK - {len(records)} processos parseados")

    if not records:
        print("\nNenhum registro encontrado. Verifique o FILE_ID e a estrutura da planilha.")
        sys.exit(1)

    print("\n[3/3] Gerando HTML...")
    html = build_html(records)
    out = Path(OUTPUT_HTML)
    out.write_text(html, encoding="utf-8")

    elapsed = (datetime.now() - t0).total_seconds()
    size_kb  = out.stat().st_size / 1024

    print(f"      OK - {out.resolve()}")
    print(f"      OK - {size_kb:.0f} KB  ({len(records)} processos  |  {elapsed:.1f}s)")

    # Resumo rapido
    ufs  = len({r["UF"] for r in records if r["UF"]})
    muns = len({r["MUNICIPIO"] for r in records if r["MUNICIPIO"]})
    val  = sum(r["VALOR_NUM"] for r in records)
    prcs = sum(1 for r in records
               if re.match(r"^\d{4}$", r["PRC"]) or r["PRC"].upper().startswith("SIM"))

    print()
    print("  +- Resumo da planilha -----------------------")
    print(f"  |  Processos   : {len(records):,}")
    print(f"  |  Estados     : {ufs}")
    print(f"  |  Municipios  : {muns:,}")
    print(f"  |  Valor total : R$ {val/1e9:.2f} B")
    print(f"  |  PRC expedido: {prcs}")
    print("  +-----------------------------------------------")
    print()
    print("  Abra o arquivo painel-fundef-acp.html no navegador.")
    print()


if __name__ == "__main__":
    main()
